from __future__ import annotations

from etf_overlap.exceptions import HoldingsNotFoundError
from etf_overlap.models import ETFHoldings
from etf_overlap.providers.base import HoldingsProvider


class MockHoldingsProvider(HoldingsProvider):
    """Simple in-memory holdings provider for tests and development."""

    def __init__(self, holdings_map: dict[str, ETFHoldings]) -> None:
        self.holdings_map = {ticker.upper(): holdings.normalized() for ticker, holdings in holdings_map.items()}

    def get_holdings(self, ticker: str) -> ETFHoldings:
        normalized_ticker = ticker.upper().strip()
        holdings = self.holdings_map.get(normalized_ticker)
        if holdings is None:
            raise HoldingsNotFoundError(f"Mock holdings missing for ETF {normalized_ticker}.")
        return holdings

